module decoder_3to8(
    input wire en,
    input wire [2:0] in,
    output reg [7:0] out
);
  wire _tap_en = en & {1{1'b1}};


    always @(*) begin
        if (en) begin
            out = 8'b00000001 << in;
        end else begin
            out = 8'b00000000;
        end
    end
endmodule
